@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600&family=Outfit:wght@500;600;700&display=swap');

@tailwind base;
@tailwind components;
@tailwind utilities;

:root {
  --font-body: 'Inter', sans-serif;
  --font-display: 'Outfit', sans-serif;

  /* Hanron brand palette - Teal & Charcoal */
  /* Base - clean white/slate */
  --background: 210 40% 98%;
  --foreground: 220 15% 20%;

  /* Primary - Hanron Teal */
  --primary: 174 58% 44%;
  --primary-foreground: 0 0% 100%;

  /* Secondary - Soft warm gray */
  --secondary: 210 20% 95%;
  --secondary-foreground: 220 15% 20%;

  /* Muted - Cool grays */
  --muted: 210 20% 95%;
  --muted-foreground: 215 10% 47%;

  /* Accent - Lighter teal */
  --accent: 174 45% 92%;
  --accent-foreground: 174 58% 30%;

  /* Destructive */
  --destructive: 0 84% 60%;
  --destructive-foreground: 0 0% 100%;

  /* Borders & Inputs */
  --border: 214 25% 89%;
  --input: 214 25% 89%;
  --ring: 174 58% 44%;

  --radius: 0.75rem;
}

.dark {
  --background: 220 20% 10%;
  --foreground: 210 30% 92%;
  --primary: 174 58% 44%;
  --primary-foreground: 0 0% 100%;
  --secondary: 220 15% 18%;
  --secondary-foreground: 210 30% 92%;
  --muted: 220 15% 18%;
  --muted-foreground: 215 15% 60%;
  --accent: 174 40% 18%;
  --accent-foreground: 174 50% 65%;
  --destructive: 0 62% 40%;
  --destructive-foreground: 0 0% 100%;
  --border: 220 12% 22%;
  --input: 220 12% 22%;
  --ring: 174 58% 44%;
}

@layer base {
  body {
    @apply bg-background text-foreground antialiased;
    font-family: var(--font-body);
  }

  h1, h2, h3, h4, h5, h6 {
    font-family: var(--font-display);
    @apply font-bold tracking-tight;
  }
}

/* Custom Scrollbar */
::-webkit-scrollbar {
  width: 8px;
  height: 8px;
}
::-webkit-scrollbar-track {
  @apply bg-transparent;
}
::-webkit-scrollbar-thumb {
  @apply bg-muted-foreground/20 rounded-full hover:bg-muted-foreground/40 transition-colors;
}

/* Glassmorphism utilities */
.glass-panel {
  @apply bg-white/70 dark:bg-black/40 backdrop-blur-xl border border-white/20 dark:border-white/10 shadow-xl;
}

/* Animation utilities */
.animate-in {
  animation: fadeIn 0.4s ease-out forwards;
}

@keyframes fadeIn {
  from { opacity: 0; transform: translateY(10px); }
  to { opacity: 1; transform: translateY(0); }
}

